mapper.select:
SELECT o.*, oi.id as item_id, oi.product_name, oi.product_pic, oi.product_price, oi.product_quantity, oi.product_attr, oi.product_sku_id FROM oms_order o LEFT JOIN oms_order_item oi ON o.id = oi.order_id
o.user_id = #{userId}
AND o.status = #{status}
AND o.is_deleted = 0
ORDER BY o.create_time DESC
